children.css:
.question-knowledge-point-page > .layout-content { overflow: hidden !important; }
.question-knowledge-point-page > .layout-content > .layout-content-inner { overflow: hidden !important; }
.question-knowledge-point-page > .layout-content > .layout-content-inner > div { height: 100% !important; min-height: 0 !important; overflow: hidden !important; }
.question-knowledge-point-page .kp-search-shell.co-ui-form { height: 100% !important; min-height: 0 !important; padding: 0 !important; box-sizing: border-box !important; background: #f8f9fa; }
.question-knowledge-point-page .kp-shell-layout.ant-layout.ant-layout-has-sider { height: 100% !important; min-height: 0 !important; align-items: stretch !important; }
.question-knowledge-point-page .kp-shell-layout > .ant-layout-sider { align-self: stretch !important; height: auto !important; min-height: 0 !important; display: flex !important; flex-direction: column !important; padding-bottom: 0 !important; }
.question-knowledge-point-page .kp-shell-layout > .ant-layout-sider > .ant-layout-sider-children { flex: 1 1 auto !important; height: auto !important; min-height: 0 !important; overflow: hidden !important; }
.question-knowledge-point-page .kp-shell-layout > .ant-layout-sider > .ant-layout-sider-trigger { position: relative !important; flex: 0 0 48px !important; height: 48px !important; line-height: 48px !important; transform: none !important; }
.question-knowledge-point-page .kp-shell-layout > .ant-layout { height: 100% !important; min-height: 0 !important; }
.question-knowledge-point-page .kp-sider-content { height: 100% !important; min-height: 0 !important; scrollbar-gutter: stable; }
.question-knowledge-point-page .kp-sider-content .co-ui-button.ant-btn { height: 34px !important; min-height: 34px !important; font-size: 13px; }
.question-knowledge-point-page .kp-sider-content .co-ui-form-item.ant-form-item { margin: 0 10px 6px !important; }
.question-knowledge-point-page .kp-sider-content .ant-select-selector { min-height: 32px !important; height: 32px !important; border-radius: 6px !important; }
.question-knowledge-point-page .kp-sider-content .ant-select-selection-item { line-height: 30px !important; }
.question-knowledge-point-page .ant-layout-sider:not(.ant-layout-sider-collapsed) .kp-sider-content { overflow-y: auto !important; overflow-x: hidden !important; }
.question-knowledge-point-page .ant-layout-sider-collapsed .kp-sider-content { padding: 8px 6px !important; gap: 8px !important; align-items: center; overflow: hidden !important; }
.question-knowledge-point-page .ant-layout-sider-collapsed .kp-sider-content > div:not(.kp-sider-bottom) { display: none !important; }
.question-knowledge-point-page .ant-layout-sider-collapsed .kp-sider-bottom { margin-top: 0 !important; border-top: 0 !important; padding: 0 !important; width: 100%; }
.question-knowledge-point-page .ant-layout-sider-collapsed .kp-sider-bottom .ant-btn { width: 40px !important; padding: 0 !important; }
.question-knowledge-point-page .ant-layout-sider-collapsed .kp-sider-bottom .ant-btn span:not(.anticon) { display: none !important; }
.question-knowledge-point-page .kp-panel-scroll-root { overflow: hidden !important; align-items: stretch !important; }
.question-knowledge-point-page [data-panel-id="knowledge-point-list-panel"],
.question-knowledge-point-page [data-panel-id="knowledge-point-editor-panel"] { height: 100% !important; min-height: 0 !important; overflow: hidden !important; }
.question-knowledge-point-page .kp-list-scroll,
.question-knowledge-point-page .kp-editor-scroll { height: 100% !important; min-height: 0 !important; overflow-y: auto !important; overflow-x: hidden !important; scrollbar-gutter: stable; }
.question-knowledge-point-page .kp-main-toolbar { flex: 0 0 auto !important; }
.question-knowledge-point-page .kp-toolbar-form.co-ui-form { padding: 0 !important; }
.question-knowledge-point-page .kp-toolbar-form .co-ui-form-item.ant-form-item { margin: 0 !important; }
.question-knowledge-point-page .kp-card { transition: border-color .16s ease, box-shadow .16s ease, background .16s ease; }
.question-knowledge-point-page .kp-chip { display: inline-flex; align-items: center; height: 22px; padding: 0 8px; border-radius: 4px; font-size: 12px; line-height: 22px; white-space: nowrap; font-weight: 700; }
.question-knowledge-point-page .kp-editor-inline .co-ui-form { padding: 0; }
.question-knowledge-point-page .kp-editor-inline .co-ui-form-item.ant-form-item { margin-bottom: 10px; margin-inline-end: 0; }
.question-knowledge-point-page .kp-editor-inline .ant-form-item-label { padding-bottom: 2px; }
.question-knowledge-point-page .kp-editor-inline .ant-form-item-label > label { height: 18px; font-size: 12px; color: #414754; }
.question-knowledge-point-page .kp-editor-inline .ant-input,
.question-knowledge-point-page .kp-editor-inline .ant-select-selector,
.question-knowledge-point-page .kp-editor-inline .ant-input-number { border-radius: 6px !important; }
.question-knowledge-point-page .bottom-tool-bar { flex: 0 0 auto !important; }
@media (max-width: 900px) {
  .question-knowledge-point-page .kp-panel-scroll-root.co-ui-panel-group { flex-direction: column !important; padding: 8px !important; }
  .question-knowledge-point-page .kp-panel-scroll-root > [data-panel-id="knowledge-point-list-panel"],
  .question-knowledge-point-page .kp-panel-scroll-root > [data-panel-id="knowledge-point-editor-panel"] { width: 100% !important; min-width: 0 !important; max-width: none !important; }
  .question-knowledge-point-page .kp-panel-scroll-root > [data-panel-id="knowledge-point-list-panel"] { flex: 0 0 220px !important; min-height: 0 !important; }
  .question-knowledge-point-page .kp-panel-scroll-root > [data-panel-id="knowledge-point-editor-panel"] { flex: 1 1 0 !important; min-height: 0 !important; }
  .question-knowledge-point-page .kp-panel-scroll-root > .co-ui-panel-resize { width: 100% !important; min-width: 0 !important; height: 8px !important; min-height: 8px !important; margin: 8px 0 !important; cursor: row-resize !important; background: linear-gradient(0deg, transparent 0, transparent 3px, #c1c6d6 3px, #c1c6d6 5px, transparent 5px) !important; }
}
@media (max-width: 760px) {
  .question-knowledge-point-page .kp-shell-layout > .ant-layout-sider { width: 52px !important; min-width: 52px !important; max-width: 52px !important; flex: 0 0 52px !important; }
  .question-knowledge-point-page .kp-sider-content { padding: 8px 6px !important; gap: 8px !important; align-items: center; overflow: hidden !important; }
  .question-knowledge-point-page .kp-sider-content > div:not(.kp-sider-bottom) { display: none !important; }
  .question-knowledge-point-page .kp-sider-bottom { margin-top: 0 !important; border-top: 0 !important; padding: 0 !important; width: 100%; }
  .question-knowledge-point-page .kp-sider-bottom .ant-btn { width: 40px !important; padding: 0 !important; }
  .question-knowledge-point-page .kp-sider-bottom .ant-btn span:not(.anticon) { display: none !important; }
}

.question-knowledge-point-page .kp-main-toolbar .co-ui-form-item.ant-form-item { margin: 0 !important; height: 32px !important; min-height: 32px !important; display: flex !important; align-items: center !important; }
.question-knowledge-point-page .kp-main-toolbar .ant-form-item-row { width: 100% !important; align-items: center !important; }
.question-knowledge-point-page .kp-main-toolbar .ant-form-item-control-input { min-height: 32px !important; }
.question-knowledge-point-page .kp-main-toolbar .ant-form-item-control-input-content { min-height: 32px !important; display: flex !important; align-items: center !important; }
.question-knowledge-point-page .kp-main-toolbar .ant-input,
.question-knowledge-point-page .kp-main-toolbar .ant-select-selector,
.question-knowledge-point-page .kp-main-toolbar .co-ui-button.ant-btn { height: 32px !important; min-height: 32px !important; }
.question-knowledge-point-page [data-panel-id="knowledge-point-editor-panel"] .layout-content,
.question-knowledge-point-page [data-panel-id="knowledge-point-editor-panel"] .layout-content-inner,
.question-knowledge-point-page [data-panel-id="knowledge-point-editor-panel"] .layout-content-inner > div { min-height: 0 !important; overflow: hidden !important; }
.question-knowledge-point-page [data-panel-id="knowledge-point-editor-panel"] .layout-content-inner > div { height: 100% !important; }
.question-knowledge-point-page .kp-editor-inline { min-height: 0 !important; overflow: hidden !important; }
.question-knowledge-point-page .kp-editor-inline > .layout-content { min-height: 0 !important; overflow: hidden !important; }
.question-knowledge-point-page .kp-editor-scroll { height: calc(100vh - 214px) !important; max-height: calc(100vh - 214px) !important; min-height: 0 !important; overflow-y: auto !important; padding: 0 8px 18px 0 !important; box-sizing: border-box !important; }
.question-knowledge-point-page .kp-content-rich-text { width: 100% !important; }
.question-knowledge-point-page .kp-content-rich-text .ql-container { max-height: 260px; overflow: auto; }
@media (min-width: 901px) {
  .question-knowledge-point-page .kp-panel-scroll-root > [data-panel-id="knowledge-point-list-panel"],
  .question-knowledge-point-page .kp-panel-scroll-root > [data-panel-id="knowledge-point-editor-panel"] { min-height: calc(100vh - 120px) !important; }
}
@media (max-width: 900px) {
  .question-knowledge-point-page .kp-editor-scroll { height: calc(100vh - 300px) !important; max-height: calc(100vh - 300px) !important; }
}

.question-knowledge-point-page .kp-shell-layout > .ant-layout-sider > .ant-layout-sider-children { display: flex !important; flex-direction: column !important; }
.question-knowledge-point-page .kp-shell-layout > .ant-layout-sider:not(.ant-layout-sider-collapsed) .kp-sider-content { flex: 1 1 auto !important; max-height: calc(100vh - 48px) !important; overflow-y: auto !important; overflow-x: hidden !important; padding-bottom: 16px !important; }
.question-knowledge-point-page .kp-toolbar-keyword { flex: 0 0 200px !important; width: 200px !important; max-width: min(200px, 42vw) !important; }
@media (max-width: 520px) {
  .question-knowledge-point-page .kp-toolbar-keyword { flex: 1 1 150px !important; width: auto !important; max-width: none !important; }
}

.question-knowledge-point-page > .layout-content > .layout-content-inner > div > div { height: 100% !important; min-height: 0 !important; overflow: hidden !important; }
.question-knowledge-point-page .kp-search-shell > .kp-shell-layout { height: 100% !important; min-height: 0 !important; }
.question-knowledge-point-page .kp-shell-layout > .ant-layout-sider { max-height: 100% !important; }
.question-knowledge-point-page .kp-shell-layout > .ant-layout-sider > .ant-layout-sider-trigger { flex: 0 0 48px !important; }
